import signal
import pytest
from source import sqrt

def timeout_handler(signum, frame):
    raise TimeoutError("Function timed out")

def test_sqrt_convergence_to_sqrt_two():
    # Set a 1 second timeout to catch infinite loops
    signal.signal(signal.SIGALRM, timeout_handler)
    signal.alarm(1)
    try:
        result = sqrt(2, 0.01)
    except TimeoutError:
        pytest.fail("sqrt(2, 0.01) did not converge within the timeout")
    else:
        assert abs(result - 1.41421356237) <= 0.01, (
            f"Expected sqrt(2) ≈ 1.41421356237 within 0.01, got {result}"
        )
    finally:
        signal.alarm(0)
